// ============================================================
// src/components/admin/BillingTab.js
// ============================================================
import React, { useState, useEffect, useCallback, useRef } from "react";
import api from "../../utils/api";

const HOSPITAL_NAME = "PearlSmile Dental Hospital";
const HOSPITAL_ADDRESS = "Dental Care Centre, Maharashtra, India";
const HOSPITAL_PHONE = "+91 87936 08083";
const HOSPITAL_GST = "GST: 27XXXXX1234X1Z5";

const DENTAL_TREATMENTS = [
  "General Checkup & Cleaning",
  "Teeth Whitening",
  "Dental Implant",
  "Root Canal Therapy",
  "Crown / Cap",
  "Bridge",
  "Orthodontic Treatment (Braces)",
  "Invisalign",
  "Tooth Extraction",
  "Wisdom Tooth Removal",
  "Composite Filling",
  "Amalgam Filling",
  "Dental X-Ray",
  "Scaling & Polishing",
  "Gum Treatment (Periodontics)",
  "Smile Makeover",
  "Veneer",
  "Pediatric Dentistry",
  "Fluoride Treatment",
  "Mouthguard / Night Guard",
  "Consultation Fee",
  "Follow-Up Visit",
  "Oral Surgery",
  "Jaw Treatment (TMJ)",
  "Emergency Dental Care",
];

const PAYMENT_METHODS = [
  { value: "cash", label: "Cash" },
  { value: "upi", label: "UPI" },
  { value: "card", label: "Card" },
  { value: "insurance", label: "Insurance" },
  { value: "other", label: "Other" },
];

const STATUS_CONFIG = {
  paid: { label: "Paid", color: "#16a34a", bg: "#f0fdf4" },
  partial: { label: "Partial", color: "#d97706", bg: "#fffbeb" },
  unpaid: { label: "Unpaid", color: "#dc2626", bg: "#fef2f2" },
};

// ---- Helpers ------------------------------------------------
function fmt(n) {
  return (
    "Rs. " +
    Number(n || 0).toLocaleString("en-IN", {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    })
  );
}

function todayISO() {
  return new Date().toISOString().split("T")[0];
}

function friendlyDate(d) {
  if (!d) return "--";
  const dt = new Date(d + "T00:00:00");
  if (isNaN(dt)) return d;
  return dt.toLocaleDateString("en-IN", {
    day: "numeric",
    month: "short",
    year: "numeric",
  });
}

function calcTotals(items, discountType, discountValue, gstPercent) {
  const subtotal = items.reduce((s, i) => s + (parseFloat(i.amount) || 0), 0);
  const discountAmount =
    discountType === "percent"
      ? (subtotal * (parseFloat(discountValue) || 0)) / 100
      : parseFloat(discountValue) || 0;
  const afterDiscount = Math.max(0, subtotal - discountAmount);
  const gstAmount = (afterDiscount * (parseFloat(gstPercent) || 0)) / 100;
  const totalAmount = afterDiscount + gstAmount;
  return { subtotal, discountAmount, gstAmount, totalAmount };
}

// ---- Shared styles ------------------------------------------
const card = {
  background: "#fff",
  border: "1px solid #e5e7eb",
  borderRadius: "10px",
  padding: "18px 20px",
  boxShadow: "0 1px 4px rgba(0,0,0,0.06)",
};
const labelSt = {
  fontSize: "11px",
  color: "#94a3b8",
  fontWeight: 600,
  textTransform: "uppercase",
  display: "block",
  marginBottom: "4px",
};
const inputSt = {
  width: "100%",
  padding: "8px 10px",
  borderRadius: "7px",
  border: "1px solid #d1d5db",
  fontSize: "13px",
  outline: "none",
  boxSizing: "border-box",
};
const btnPrimary = {
  padding: "9px 20px",
  borderRadius: "8px",
  background: "#1e40af",
  color: "#fff",
  border: "none",
  fontSize: "13px",
  fontWeight: 700,
  cursor: "pointer",
};
const btnGhost = {
  padding: "8px 16px",
  borderRadius: "8px",
  background: "#f1f5f9",
  color: "#374151",
  border: "1px solid #d1d5db",
  fontSize: "13px",
  fontWeight: 600,
  cursor: "pointer",
};

// ---- Patient Picker Modal -----------------------------------
function PatientPickerModal({ patients, onSelect, onClose }) {
  const [q, setQ] = useState("");
  const filtered = patients.filter(
    (p) =>
      (p.name || "").toLowerCase().includes(q.toLowerCase()) ||
      (p.mobile || "").includes(q),
  );
  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        background: "rgba(0,0,0,0.5)",
        zIndex: 9000,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        padding: "16px",
      }}
    >
      <div
        style={{
          background: "#fff",
          borderRadius: "12px",
          width: "100%",
          maxWidth: "480px",
          maxHeight: "80vh",
          display: "flex",
          flexDirection: "column",
          boxShadow: "0 8px 40px rgba(0,0,0,0.2)",
        }}
      >
        <div
          style={{
            padding: "16px 20px",
            borderBottom: "1px solid #e5e7eb",
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
          }}
        >
          <span style={{ fontWeight: 700, fontSize: "15px", color: "#1e293b" }}>
            Select Patient
          </span>
          <button
            onClick={onClose}
            style={{
              background: "none",
              border: "none",
              fontSize: "20px",
              cursor: "pointer",
              color: "#94a3b8",
            }}
          >
            x
          </button>
        </div>
        <div
          style={{ padding: "12px 20px", borderBottom: "1px solid #f1f5f9" }}
        >
          <input
            value={q}
            onChange={(e) => setQ(e.target.value)}
            placeholder="Search by name or phone..."
            style={{ ...inputSt }}
            autoFocus
          />
        </div>
        <div style={{ overflowY: "auto", flex: 1 }}>
          {filtered.length === 0 ? (
            <div
              style={{
                padding: "30px",
                textAlign: "center",
                color: "#94a3b8",
                fontSize: "13px",
              }}
            >
              No patients found
            </div>
          ) : (
            filtered.map((p) => (
              <div
                key={p._id}
                onClick={() => onSelect(p)}
                style={{
                  padding: "12px 20px",
                  borderBottom: "1px solid #f8fafc",
                  cursor: "pointer",
                  display: "flex",
                  justifyContent: "space-between",
                  alignItems: "center",
                }}
                onMouseEnter={(e) =>
                  (e.currentTarget.style.background = "#f0f9ff")
                }
                onMouseLeave={(e) =>
                  (e.currentTarget.style.background = "#fff")
                }
              >
                <div>
                  <div
                    style={{
                      fontWeight: 600,
                      fontSize: "14px",
                      color: "#1e293b",
                    }}
                  >
                    {p.name}
                  </div>
                  <div
                    style={{
                      fontSize: "12px",
                      color: "#64748b",
                      marginTop: "2px",
                    }}
                  >
                    {p.mobile}
                    {p.age ? ` | Age: ${p.age}` : ""}
                    {p.gender ? ` | ${p.gender}` : ""}
                  </div>
                </div>
                <div style={{ fontSize: "11px", color: "#94a3b8" }}>
                  {p.visits?.length || 0} visits
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
}

// ---- Invoice Form -------------------------------------------
function InvoiceForm({
  patients,
  doctor,
  invoice,
  onSave,
  onCancel,
  showNotify,
}) {
  const isEdit = !!invoice;

  const [selectedPatient, setSelectedPatient] = useState(null);
  const [showPicker, setShowPicker] = useState(false);
  const [saving, setSaving] = useState(false);

  const [form, setForm] = useState({
    patientId: "",
    patientName: "",
    patientPhone: "",
    patientAge: "",
    patientGender: "",
    doctorName: doctor?.name || "",
    doctorId: doctor?.doctorId || "",
    invoiceDate: todayISO(),
    discountType: "flat",
    discountValue: "0",
    gstPercent: "0",
    paymentStatus: "unpaid",
    paymentMethod: "cash",
    amountPaid: "0",
    paymentDate: todayISO(),
    receiptNumber: "",
    upiId: "",
    insuranceProvider: "",
    insuranceClaimNo: "",
    insuranceStatus: "",
    notes: "",
  });

  const [items, setItems] = useState([
    { treatment: "", quantity: "1", rate: "", amount: "0" },
  ]);

  // Populate form when editing
  useEffect(() => {
    if (invoice) {
      setForm({
        patientId: invoice.patientId || "",
        patientName: invoice.patientName || "",
        patientPhone: invoice.patientPhone || "",
        patientAge: invoice.patientAge || "",
        patientGender: invoice.patientGender || "",
        doctorName: invoice.doctorName || doctor?.name || "",
        doctorId: invoice.doctorId || doctor?.doctorId || "",
        invoiceDate: invoice.invoiceDate || todayISO(),
        discountType: invoice.discountType || "flat",
        discountValue: String(invoice.discountValue || 0),
        gstPercent: String(invoice.gstPercent || 0),
        paymentStatus: invoice.paymentStatus || "unpaid",
        paymentMethod: invoice.paymentMethod || "cash",
        amountPaid: String(invoice.amountPaid || 0),
        paymentDate: invoice.paymentDate || todayISO(),
        receiptNumber: invoice.receiptNumber || "",
        upiId: invoice.upiId || "",
        insuranceProvider: invoice.insuranceProvider || "",
        insuranceClaimNo: invoice.insuranceClaimNo || "",
        insuranceStatus: invoice.insuranceStatus || "",
        notes: invoice.notes || "",
      });
      setItems(
        (invoice.items || []).map((i) => ({
          treatment: i.treatment,
          quantity: String(i.quantity),
          rate: String(i.rate),
          amount: String(i.amount),
        })),
      );
    }
  }, [invoice]);

  function setF(key, val) {
    setForm((f) => ({ ...f, [key]: val }));
  }

  function pickPatient(p) {
    setSelectedPatient(p);
    setForm((f) => ({
      ...f,
      patientId: p._id,
      patientName: p.name,
      patientPhone: p.mobile || "",
      patientAge: p.age || "",
      patientGender: p.gender || "",
    }));
    setShowPicker(false);
  }

  function updateItem(idx, key, val) {
    setItems((prev) => {
      const arr = [...prev];
      arr[idx] = { ...arr[idx], [key]: val };
      if (key === "quantity" || key === "rate") {
        const q = parseFloat(key === "quantity" ? val : arr[idx].quantity) || 0;
        const r = parseFloat(key === "rate" ? val : arr[idx].rate) || 0;
        arr[idx].amount = String((q * r).toFixed(2));
      }
      return arr;
    });
  }

  function addItem() {
    setItems((p) => [
      ...p,
      { treatment: "", quantity: "1", rate: "", amount: "0" },
    ]);
  }
  function removeItem(idx) {
    setItems((p) => p.filter((_, i) => i !== idx));
  }

  const { subtotal, discountAmount, gstAmount, totalAmount } = calcTotals(
    items,
    form.discountType,
    form.discountValue,
    form.gstPercent,
  );

  const amountDue = Math.max(
    0,
    totalAmount - (parseFloat(form.amountPaid) || 0),
  );

  async function handleSave() {
    if (!form.patientId) {
      showNotify("Error", "Please select a patient.", true);
      return;
    }
    if (items.some((i) => !i.treatment || !i.rate)) {
      showNotify(
        "Error",
        "Fill in treatment and rate for all line items.",
        true,
      );
      return;
    }
    setSaving(true);
    try {
      const payload = {
        ...form,
        discountValue: parseFloat(form.discountValue) || 0,
        gstPercent: parseFloat(form.gstPercent) || 0,
        amountPaid: parseFloat(form.amountPaid) || 0,
        items: items.map((i) => ({
          treatment: i.treatment,
          quantity: parseFloat(i.quantity) || 1,
          rate: parseFloat(i.rate) || 0,
          amount: parseFloat(i.amount) || 0,
        })),
        subtotal,
        discountAmount,
        gstAmount,
        totalAmount,
        amountDue,
      };

      // auto payment status
      if (payload.amountPaid >= totalAmount && totalAmount > 0)
        payload.paymentStatus = "paid";
      else if (payload.amountPaid > 0) payload.paymentStatus = "partial";
      else payload.paymentStatus = "unpaid";

      if (isEdit) {
        await api.put(`/billing/${invoice._id}`, payload);
        showNotify("Saved", "Invoice updated successfully.");
      } else {
        await api.post("/billing", payload);
        showNotify("Created", "Invoice created successfully.");
      }
      onSave();
    } catch (err) {
      showNotify("Error", err.message, true);
    }
    setSaving(false);
  }

  return (
    <div>
      {showPicker && (
        <PatientPickerModal
          patients={patients}
          onSelect={pickPatient}
          onClose={() => setShowPicker(false)}
        />
      )}

      {/* Header */}
      <div
        style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
          marginBottom: "20px",
          flexWrap: "wrap",
          gap: "10px",
        }}
      >
        <h3 style={{ margin: 0, color: "#1e293b", fontSize: "17px" }}>
          {isEdit ? "Edit Invoice" : "New Invoice"}
        </h3>
        <div style={{ display: "flex", gap: "8px" }}>
          <button onClick={onCancel} style={btnGhost}>
            Cancel
          </button>
          <button
            onClick={handleSave}
            disabled={saving}
            style={{ ...btnPrimary, opacity: saving ? 0.7 : 1 }}
          >
            {saving
              ? "Saving..."
              : isEdit
                ? "Update Invoice"
                : "Create Invoice"}
          </button>
        </div>
      </div>

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit,minmax(300px,1fr))",
          gap: "16px",
        }}
      >
        {/* Patient */}
        <div style={card}>
          <div
            style={{
              fontWeight: 700,
              fontSize: "13px",
              color: "#1e40af",
              marginBottom: "12px",
              textTransform: "uppercase",
              letterSpacing: "0.5px",
            }}
          >
            Patient Details
          </div>
          <button
            onClick={() => setShowPicker(true)}
            style={{
              ...btnGhost,
              width: "100%",
              marginBottom: "12px",
              textAlign: "left",
            }}
          >
            {form.patientName
              ? form.patientName + " — " + form.patientPhone
              : "Select Patient from Profile..."}
          </button>
          {form.patientName && (
            <div
              style={{
                background: "#f0f9ff",
                border: "1px solid #bae6fd",
                borderRadius: "7px",
                padding: "10px 12px",
                fontSize: "12px",
                color: "#0369a1",
              }}
            >
              <strong>{form.patientName}</strong> &nbsp;|&nbsp;{" "}
              {form.patientPhone}
              {form.patientAge ? ` | Age: ${form.patientAge}` : ""}
              {form.patientGender ? ` | ${form.patientGender}` : ""}
            </div>
          )}
        </div>

        {/* Invoice info */}
        <div style={card}>
          <div
            style={{
              fontWeight: 700,
              fontSize: "13px",
              color: "#1e40af",
              marginBottom: "12px",
              textTransform: "uppercase",
              letterSpacing: "0.5px",
            }}
          >
            Invoice Details
          </div>
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "1fr 1fr",
              gap: "10px",
            }}
          >
            <div>
              <label style={labelSt}>Invoice Date</label>
              <input
                type="date"
                value={form.invoiceDate}
                onChange={(e) => setF("invoiceDate", e.target.value)}
                style={inputSt}
              />
            </div>
            <div>
              <label style={labelSt}>Doctor</label>
              <input
                value={form.doctorName}
                onChange={(e) => setF("doctorName", e.target.value)}
                style={inputSt}
              />
            </div>
          </div>
        </div>
      </div>

      {/* Line items */}
      <div style={{ ...card, marginTop: "16px" }}>
        <div
          style={{
            fontWeight: 700,
            fontSize: "13px",
            color: "#1e40af",
            marginBottom: "14px",
            textTransform: "uppercase",
            letterSpacing: "0.5px",
          }}
        >
          Treatments / Services
        </div>

        {/* Table header */}
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "3fr 80px 100px 100px 36px",
            gap: "8px",
            marginBottom: "6px",
            padding: "0 2px",
          }}
        >
          {["Treatment", "Qty", "Rate (Rs.)", "Amount", ""].map((h, i) => (
            <div
              key={i}
              style={{
                fontSize: "11px",
                color: "#94a3b8",
                fontWeight: 600,
                textTransform: "uppercase",
              }}
            >
              {h}
            </div>
          ))}
        </div>

        {items.map((item, idx) => (
          <div
            key={idx}
            style={{
              display: "grid",
              gridTemplateColumns: "3fr 80px 100px 100px 36px",
              gap: "8px",
              marginBottom: "8px",
              alignItems: "center",
            }}
          >
            {/* Treatment with datalist */}
            <div style={{ position: "relative" }}>
              <input
                list={`tx-list-${idx}`}
                value={item.treatment}
                onChange={(e) => updateItem(idx, "treatment", e.target.value)}
                placeholder="Type or select treatment..."
                style={inputSt}
              />
              <datalist id={`tx-list-${idx}`}>
                {DENTAL_TREATMENTS.map((t) => (
                  <option key={t} value={t} />
                ))}
              </datalist>
            </div>
            <input
              type="number"
              min="1"
              value={item.quantity}
              onChange={(e) => updateItem(idx, "quantity", e.target.value)}
              style={inputSt}
            />
            <input
              type="number"
              min="0"
              value={item.rate}
              onChange={(e) => updateItem(idx, "rate", e.target.value)}
              placeholder="0"
              style={inputSt}
            />
            <input
              readOnly
              value={fmt(item.amount)}
              style={{ ...inputSt, background: "#f8fafc", fontWeight: 600 }}
            />
            <button
              onClick={() => removeItem(idx)}
              disabled={items.length === 1}
              style={{
                padding: "6px",
                borderRadius: "6px",
                background: "#fef2f2",
                border: "1px solid #fca5a5",
                color: "#dc2626",
                cursor: items.length === 1 ? "default" : "pointer",
                fontSize: "13px",
                fontWeight: 700,
              }}
            >
              x
            </button>
          </div>
        ))}

        <button
          onClick={addItem}
          style={{ ...btnGhost, marginTop: "6px", fontSize: "12px" }}
        >
          + Add Treatment
        </button>
      </div>

      {/* Discount / GST / Totals */}
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit,minmax(280px,1fr))",
          gap: "16px",
          marginTop: "16px",
        }}
      >
        <div style={card}>
          <div
            style={{
              fontWeight: 700,
              fontSize: "13px",
              color: "#1e40af",
              marginBottom: "12px",
              textTransform: "uppercase",
              letterSpacing: "0.5px",
            }}
          >
            Discount & Tax
          </div>
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "1fr 1fr",
              gap: "10px",
            }}
          >
            <div>
              <label style={labelSt}>Discount Type</label>
              <select
                value={form.discountType}
                onChange={(e) => setF("discountType", e.target.value)}
                style={inputSt}
              >
                <option value="flat">Flat (Rs.)</option>
                <option value="percent">Percentage (%)</option>
              </select>
            </div>
            <div>
              <label style={labelSt}>Discount Value</label>
              <input
                type="number"
                min="0"
                value={form.discountValue}
                onChange={(e) => setF("discountValue", e.target.value)}
                style={inputSt}
              />
            </div>
            <div>
              <label style={labelSt}>GST (%)</label>
              <input
                type="number"
                min="0"
                max="100"
                value={form.gstPercent}
                onChange={(e) => setF("gstPercent", e.target.value)}
                style={inputSt}
              />
            </div>
          </div>
        </div>

        {/* Totals box */}
        <div style={{ ...card, background: "#f8fafc" }}>
          <div
            style={{
              fontWeight: 700,
              fontSize: "13px",
              color: "#1e40af",
              marginBottom: "12px",
              textTransform: "uppercase",
              letterSpacing: "0.5px",
            }}
          >
            Summary
          </div>
          {[
            ["Subtotal", fmt(subtotal)],
            ["Discount", `- ${fmt(discountAmount)}`],
            ["GST", `+ ${fmt(gstAmount)}`],
          ].map(([k, v]) => (
            <div
              key={k}
              style={{
                display: "flex",
                justifyContent: "space-between",
                fontSize: "13px",
                color: "#475569",
                marginBottom: "6px",
              }}
            >
              <span>{k}</span>
              <span>{v}</span>
            </div>
          ))}
          <div
            style={{
              display: "flex",
              justifyContent: "space-between",
              fontSize: "16px",
              fontWeight: 800,
              color: "#1e293b",
              borderTop: "2px solid #e5e7eb",
              paddingTop: "8px",
              marginTop: "6px",
            }}
          >
            <span>Total</span>
            <span style={{ color: "#1e40af" }}>{fmt(totalAmount)}</span>
          </div>
        </div>
      </div>

      {/* Payment */}
      <div style={{ ...card, marginTop: "16px" }}>
        <div
          style={{
            fontWeight: 700,
            fontSize: "13px",
            color: "#1e40af",
            marginBottom: "12px",
            textTransform: "uppercase",
            letterSpacing: "0.5px",
          }}
        >
          Payment Details
        </div>
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fit,minmax(160px,1fr))",
            gap: "10px",
          }}
        >
          <div>
            <label style={labelSt}>Payment Method</label>
            <select
              value={form.paymentMethod}
              onChange={(e) => setF("paymentMethod", e.target.value)}
              style={inputSt}
            >
              {PAYMENT_METHODS.map((m) => (
                <option key={m.value} value={m.value}>
                  {m.label}
                </option>
              ))}
            </select>
          </div>
          <div>
            <label style={labelSt}>Amount Paid (Rs.)</label>
            <input
              type="number"
              min="0"
              value={form.amountPaid}
              onChange={(e) => setF("amountPaid", e.target.value)}
              style={inputSt}
            />
          </div>
          <div>
            <label style={labelSt}>Amount Due</label>
            <input
              readOnly
              value={fmt(amountDue)}
              style={{
                ...inputSt,
                background: "#fef2f2",
                fontWeight: 700,
                color: amountDue > 0 ? "#dc2626" : "#16a34a",
              }}
            />
          </div>
          <div>
            <label style={labelSt}>Payment Date</label>
            <input
              type="date"
              value={form.paymentDate}
              onChange={(e) => setF("paymentDate", e.target.value)}
              style={inputSt}
            />
          </div>
          <div>
            <label style={labelSt}>Receipt No.</label>
            <input
              value={form.receiptNumber}
              onChange={(e) => setF("receiptNumber", e.target.value)}
              placeholder="e.g. RCP-001"
              style={inputSt}
            />
          </div>
          {form.paymentMethod === "upi" && (
            <div>
              <label style={labelSt}>UPI ID</label>
              <input
                value={form.upiId}
                onChange={(e) => setF("upiId", e.target.value)}
                placeholder="name@upi"
                style={inputSt}
              />
            </div>
          )}
        </div>
      </div>

      {/* Insurance (optional) */}
      <div style={{ ...card, marginTop: "16px" }}>
        <div
          style={{
            fontWeight: 700,
            fontSize: "13px",
            color: "#1e40af",
            marginBottom: "12px",
            textTransform: "uppercase",
            letterSpacing: "0.5px",
          }}
        >
          Insurance (Optional)
        </div>
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fit,minmax(180px,1fr))",
            gap: "10px",
          }}
        >
          <div>
            <label style={labelSt}>Insurance Provider</label>
            <input
              value={form.insuranceProvider}
              onChange={(e) => setF("insuranceProvider", e.target.value)}
              placeholder="Provider name"
              style={inputSt}
            />
          </div>
          <div>
            <label style={labelSt}>Claim Number</label>
            <input
              value={form.insuranceClaimNo}
              onChange={(e) => setF("insuranceClaimNo", e.target.value)}
              placeholder="Claim no."
              style={inputSt}
            />
          </div>
          <div>
            <label style={labelSt}>Claim Status</label>
            <select
              value={form.insuranceStatus}
              onChange={(e) => setF("insuranceStatus", e.target.value)}
              style={inputSt}
            >
              <option value="">Not Applicable</option>
              <option value="pending">Pending</option>
              <option value="approved">Approved</option>
              <option value="rejected">Rejected</option>
            </select>
          </div>
        </div>
      </div>

      {/* Notes */}
      <div style={{ ...card, marginTop: "16px" }}>
        <label style={labelSt}>Notes / Remarks</label>
        <textarea
          value={form.notes}
          onChange={(e) => setF("notes", e.target.value)}
          placeholder="Any additional notes..."
          rows={3}
          style={{ ...inputSt, resize: "vertical" }}
        />
      </div>

      {/* Bottom save */}
      <div
        style={{
          display: "flex",
          justifyContent: "flex-end",
          gap: "10px",
          marginTop: "20px",
        }}
      >
        <button onClick={onCancel} style={btnGhost}>
          Cancel
        </button>
        <button
          onClick={handleSave}
          disabled={saving}
          style={{ ...btnPrimary, opacity: saving ? 0.7 : 1 }}
        >
          {saving ? "Saving..." : isEdit ? "Update Invoice" : "Create Invoice"}
        </button>
      </div>
    </div>
  );
}

// ---- PDF Print Invoice --------------------------------------
function printInvoice(inv) {
  const itemRows = (inv.items || [])
    .map(
      (i) =>
        `<tr>
      <td style="padding:8px 10px;border-bottom:1px solid #e5e7eb">${i.treatment}</td>
      <td style="padding:8px 10px;border-bottom:1px solid #e5e7eb;text-align:center">${i.quantity}</td>
      <td style="padding:8px 10px;border-bottom:1px solid #e5e7eb;text-align:right">Rs. ${Number(i.rate).toLocaleString("en-IN", { minimumFractionDigits: 2 })}</td>
      <td style="padding:8px 10px;border-bottom:1px solid #e5e7eb;text-align:right">Rs. ${Number(i.amount).toLocaleString("en-IN", { minimumFractionDigits: 2 })}</td>
    </tr>`,
    )
    .join("");

  const html = `<!DOCTYPE html><html><head><meta charset="utf-8"><title>Invoice ${inv.invoiceNumber}</title>
  <style>
    body{font-family:Arial,sans-serif;margin:0;padding:0;color:#1e293b;font-size:13px}
    .page{max-width:700px;margin:0 auto;padding:30px 36px}
    .header{background:#1e3a8a;color:#fff;padding:20px 24px;border-radius:8px;margin-bottom:24px;display:flex;justify-content:space-between;align-items:center}
    .header h1{margin:0;font-size:20px}
    .header p{margin:4px 0 0;font-size:11px;opacity:.85}
    .inv-meta{display:flex;justify-content:space-between;margin-bottom:20px;gap:20px;flex-wrap:wrap}
    .box{background:#f8fafc;border:1px solid #e5e7eb;border-radius:8px;padding:12px 16px;flex:1;min-width:180px}
    .box h4{margin:0 0 8px;font-size:11px;color:#94a3b8;text-transform:uppercase;letter-spacing:.5px}
    .box p{margin:2px 0;font-size:13px}
    table{width:100%;border-collapse:collapse;margin-bottom:16px}
    thead tr{background:#1e3a8a;color:#fff}
    thead th{padding:10px;text-align:left;font-size:12px}
    .totals{display:flex;justify-content:flex-end}
    .totals table{width:260px}
    .totals td{padding:5px 10px;font-size:13px}
    .totals .grand{font-weight:700;font-size:15px;color:#1e3a8a;border-top:2px solid #1e3a8a}
    .pay-badge{display:inline-block;padding:4px 12px;border-radius:20px;font-size:12px;font-weight:700}
    .paid{background:#dcfce7;color:#16a34a} .partial{background:#fef9c3;color:#d97706} .unpaid{background:#fee2e2;color:#dc2626}
    .footer{margin-top:28px;border-top:2px solid #1e3a8a;padding-top:14px;text-align:center;font-size:11px;color:#94a3b8}
    @media print{body{padding:0}.page{padding:20px}}
  </style></head><body><div class="page">
  <div class="header">
    <div><h1>${HOSPITAL_NAME}</h1><p>${HOSPITAL_ADDRESS}</p><p>${HOSPITAL_PHONE} &nbsp;|&nbsp; ${HOSPITAL_GST}</p></div>
    <div style="text-align:right"><div style="font-size:22px;font-weight:800">INVOICE</div><div style="font-size:15px;margin-top:4px">${inv.invoiceNumber}</div></div>
  </div>
  <div class="inv-meta">
    <div class="box"><h4>Patient</h4><p><strong>${inv.patientName}</strong></p><p>${inv.patientPhone || ""}${inv.patientAge ? " | Age: " + inv.patientAge : ""}${inv.patientGender ? " | " + inv.patientGender : ""}</p></div>
    <div class="box"><h4>Invoice Info</h4><p>Date: <strong>${friendlyDate(inv.invoiceDate)}</strong></p><p>Doctor: ${inv.doctorName || "--"}</p></div>
    <div class="box"><h4>Payment Status</h4><p><span class="pay-badge ${inv.paymentStatus}">${(inv.paymentStatus || "").toUpperCase()}</span></p><p>Method: ${inv.paymentMethod || "--"}</p>${inv.receiptNumber ? "<p>Receipt: " + inv.receiptNumber + "</p>" : ""}</div>
  </div>
  <table><thead><tr><th>Treatment</th><th style="text-align:center">Qty</th><th style="text-align:right">Rate</th><th style="text-align:right">Amount</th></tr></thead><tbody>${itemRows}</tbody></table>
  <div class="totals"><table>
    <tr><td>Subtotal</td><td style="text-align:right">Rs. ${Number(inv.subtotal || 0).toLocaleString("en-IN", { minimumFractionDigits: 2 })}</td></tr>
    ${(inv.discountAmount || 0) > 0 ? `<tr><td>Discount</td><td style="text-align:right;color:#dc2626">- Rs. ${Number(inv.discountAmount).toLocaleString("en-IN", { minimumFractionDigits: 2 })}</td></tr>` : ""}
    ${(inv.gstAmount || 0) > 0 ? `<tr><td>GST (${inv.gstPercent || 0}%)</td><td style="text-align:right">+ Rs. ${Number(inv.gstAmount).toLocaleString("en-IN", { minimumFractionDigits: 2 })}</td></tr>` : ""}
    <tr class="grand"><td>Total</td><td style="text-align:right">Rs. ${Number(inv.totalAmount || 0).toLocaleString("en-IN", { minimumFractionDigits: 2 })}</td></tr>
    <tr><td style="color:#16a34a">Amount Paid</td><td style="text-align:right;color:#16a34a">Rs. ${Number(inv.amountPaid || 0).toLocaleString("en-IN", { minimumFractionDigits: 2 })}</td></tr>
    ${(inv.amountDue || 0) > 0 ? `<tr><td style="color:#dc2626">Amount Due</td><td style="text-align:right;color:#dc2626">Rs. ${Number(inv.amountDue).toLocaleString("en-IN", { minimumFractionDigits: 2 })}</td></tr>` : ""}
  </table></div>
  ${inv.notes ? `<div style="background:#f8fafc;border:1px solid #e5e7eb;border-radius:6px;padding:10px 14px;font-size:12px;color:#475569;margin-top:10px"><strong>Notes:</strong> ${inv.notes}</div>` : ""}
  <div class="footer"><p>Thank you for choosing ${HOSPITAL_NAME}. Your smile is our priority.</p></div>
  </div></body></html>`;

  const win = window.open("", "_blank");
  win.document.write(html);
  win.document.close();
  setTimeout(() => win.print(), 600);
}

// ---- Invoice List Row ---------------------------------------
function InvoiceRow({ inv, onEdit, onDelete, onPrint }) {
  const cfg = STATUS_CONFIG[inv.paymentStatus] || STATUS_CONFIG.unpaid;
  return (
    <div
      style={{
        ...card,
        marginBottom: "10px",
        borderLeft: `4px solid ${cfg.color}`,
        display: "flex",
        flexWrap: "wrap",
        gap: "12px",
        alignItems: "center",
      }}
    >
      <div style={{ flex: "0 0 110px" }}>
        <div style={{ fontSize: "12px", color: "#94a3b8", fontWeight: 600 }}>
          Invoice No.
        </div>
        <div style={{ fontWeight: 700, fontSize: "14px", color: "#1e40af" }}>
          {inv.invoiceNumber}
        </div>
        <div style={{ fontSize: "11px", color: "#94a3b8", marginTop: "2px" }}>
          {friendlyDate(inv.invoiceDate)}
        </div>
      </div>
      <div style={{ flex: "1 1 160px" }}>
        <div style={{ fontWeight: 700, fontSize: "14px", color: "#1e293b" }}>
          {inv.patientName}
        </div>
        <div style={{ fontSize: "12px", color: "#64748b" }}>
          {inv.patientPhone}
        </div>
        <div style={{ fontSize: "11px", color: "#94a3b8", marginTop: "2px" }}>
          Dr. {inv.doctorName}
        </div>
      </div>
      <div style={{ flex: "1 1 180px" }}>
        <div style={{ fontSize: "11px", color: "#94a3b8", fontWeight: 600 }}>
          Services
        </div>
        <div style={{ fontSize: "12px", color: "#475569" }}>
          {(inv.items || [])
            .map((i) => i.treatment)
            .join(", ")
            .slice(0, 60) || "--"}
        </div>
      </div>
      <div style={{ flex: "0 0 100px", textAlign: "right" }}>
        <div style={{ fontWeight: 800, fontSize: "15px", color: "#1e293b" }}>
          {fmt(inv.totalAmount)}
        </div>
        {(inv.amountDue || 0) > 0 && (
          <div style={{ fontSize: "11px", color: "#dc2626", fontWeight: 600 }}>
            Due: {fmt(inv.amountDue)}
          </div>
        )}
      </div>
      <div style={{ flex: "0 0 auto" }}>
        <span
          style={{
            padding: "3px 10px",
            borderRadius: "12px",
            background: cfg.bg,
            color: cfg.color,
            border: `1px solid ${cfg.color}`,
            fontSize: "11px",
            fontWeight: 700,
          }}
        >
          {cfg.label}
        </span>
      </div>
      <div style={{ display: "flex", gap: "6px", flex: "0 0 auto" }}>
        <button
          onClick={() => onPrint(inv)}
          style={{ ...btnGhost, padding: "5px 12px", fontSize: "12px" }}
        >
          Print
        </button>
        <button
          onClick={() => onEdit(inv)}
          style={{ ...btnGhost, padding: "5px 12px", fontSize: "12px" }}
        >
          Edit
        </button>
        <button
          onClick={() => onDelete(inv._id)}
          style={{
            padding: "5px 10px",
            borderRadius: "8px",
            background: "#fef2f2",
            color: "#dc2626",
            border: "1px solid #fca5a5",
            fontSize: "12px",
            fontWeight: 600,
            cursor: "pointer",
          }}
        >
          Del
        </button>
      </div>
    </div>
  );
}

// ---- Summary Cards ------------------------------------------
function SummaryCards({ summary }) {
  if (!summary) return null;
  const cards = [
    {
      label: "Total Revenue",
      value: fmt(summary.totalRevenue),
      color: "#16a34a",
    },
    {
      label: "This Month",
      value: fmt(summary.monthlyRevenue),
      color: "#2563eb",
    },
    { label: "This Week", value: fmt(summary.weeklyRevenue), color: "#7c3aed" },
    { label: "Today", value: fmt(summary.dailyRevenue), color: "#0891b2" },
    {
      label: "Outstanding Dues",
      value: fmt(summary.totalOutstanding),
      color: "#dc2626",
    },
    { label: "Unpaid Invoices", value: summary.unpaidCount, color: "#dc2626" },
    { label: "Partial", value: summary.partialCount, color: "#d97706" },
    { label: "Paid", value: summary.paidCount, color: "#16a34a" },
  ];
  return (
    <div
      style={{
        display: "grid",
        gridTemplateColumns: "repeat(auto-fit,minmax(130px,1fr))",
        gap: "10px",
        marginBottom: "24px",
      }}
    >
      {cards.map((c) => (
        <div
          key={c.label}
          style={{
            background: "#fff",
            border: "1px solid #e5e7eb",
            borderTop: `3px solid ${c.color}`,
            borderRadius: "8px",
            padding: "12px",
            textAlign: "center",
            boxShadow: "0 1px 3px rgba(0,0,0,0.05)",
          }}
        >
          <div style={{ fontSize: "18px", fontWeight: 800, color: c.color }}>
            {c.value}
          </div>
          <div
            style={{
              fontSize: "10px",
              color: "#94a3b8",
              fontWeight: 600,
              marginTop: "2px",
            }}
          >
            {c.label}
          </div>
        </div>
      ))}
    </div>
  );
}

// ---- Main BillingTab ----------------------------------------
export default function BillingTab({ showNotify, doctor }) {
  const [view, setView] = useState("list"); // list | new | edit
  const [invoices, setInvoices] = useState([]);
  const [patients, setPatients] = useState([]);
  const [summary, setSummary] = useState(null);
  const [loading, setLoading] = useState(true);
  const [editing, setEditing] = useState(null);

  // Filters
  const [search, setSearch] = useState("");
  const [filterStatus, setFilterStatus] = useState("all");
  const [filterPatient, setFilterPatient] = useState("");

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const [inv, pat, sum] = await Promise.all([
        api.get("/billing"),
        api.get("/billing/patients"),
        api.get("/billing/summary"),
      ]);
      setInvoices(Array.isArray(inv) ? inv : []);
      setPatients(Array.isArray(pat) ? pat : []);
      setSummary(sum);
    } catch (err) {
      showNotify("Error", err.message, true);
    }
    setLoading(false);
  }, [showNotify]);

  useEffect(() => {
    load();
  }, [load]);

  async function handleDelete(id) {
    if (!window.confirm("Delete this invoice permanently?")) return;
    try {
      await api.delete(`/billing/${id}`);
      setInvoices((p) => p.filter((i) => i._id !== id));
      showNotify("Deleted", "Invoice removed.");
      load();
    } catch (err) {
      showNotify("Error", err.message, true);
    }
  }

  function handleEdit(inv) {
    setEditing(inv);
    setView("edit");
  }
  function handleNew() {
    setEditing(null);
    setView("new");
  }

  function handleSaved() {
    setView("list");
    setEditing(null);
    load();
  }

  // Filtered list
  const filtered = invoices.filter((inv) => {
    const q = search.toLowerCase();
    const matchSearch =
      !q ||
      (inv.patientName || "").toLowerCase().includes(q) ||
      (inv.invoiceNumber || "").toLowerCase().includes(q) ||
      (inv.patientPhone || "").includes(q);
    const matchStatus =
      filterStatus === "all" || inv.paymentStatus === filterStatus;
    const matchPatient = !filterPatient || inv.patientId === filterPatient;
    return matchSearch && matchStatus && matchPatient;
  });

  // Patient totals for history sidebar
  const patientTotals = {};
  invoices.forEach((inv) => {
    if (!patientTotals[inv.patientId])
      patientTotals[inv.patientId] = {
        name: inv.patientName,
        total: 0,
        count: 0,
      };
    patientTotals[inv.patientId].total += inv.totalAmount || 0;
    patientTotals[inv.patientId].count += 1;
  });

  if (view === "new" || view === "edit") {
    return (
      <div style={{ padding: "0 0 40px" }}>
        <InvoiceForm
          patients={patients}
          doctor={doctor}
          invoice={view === "edit" ? editing : null}
          onSave={handleSaved}
          onCancel={() => setView("list")}
          showNotify={showNotify}
        />
      </div>
    );
  }

  return (
    <div style={{ padding: "0 0 40px" }}>
      {/* Summary cards */}
      <SummaryCards summary={summary} />

      {/* Top bar */}
      <div
        style={{
          display: "flex",
          flexWrap: "wrap",
          gap: "10px",
          marginBottom: "16px",
          alignItems: "center",
        }}
      >
        <input
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          placeholder="Search by patient, invoice number, phone..."
          style={{ ...inputSt, flex: "1 1 220px" }}
        />
        <select
          value={filterStatus}
          onChange={(e) => setFilterStatus(e.target.value)}
          style={{ ...inputSt, width: "auto" }}
        >
          <option value="all">All Statuses</option>
          {Object.entries(STATUS_CONFIG).map(([k, c]) => (
            <option key={k} value={k}>
              {c.label}
            </option>
          ))}
        </select>
        <select
          value={filterPatient}
          onChange={(e) => setFilterPatient(e.target.value)}
          style={{ ...inputSt, width: "auto", maxWidth: "200px" }}
        >
          <option value="">All Patients</option>
          {patients.map((p) => (
            <option key={p._id} value={p._id}>
              {p.name}
            </option>
          ))}
        </select>
        <button onClick={load} style={btnGhost}>
          Refresh
        </button>
        <button onClick={handleNew} style={btnPrimary}>
          + New Invoice
        </button>
      </div>

      {loading ? (
        <div
          style={{
            textAlign: "center",
            padding: "40px",
            color: "#94a3b8",
            fontSize: "15px",
          }}
        >
          Loading invoices...
        </div>
      ) : filtered.length === 0 ? (
        <div
          style={{
            textAlign: "center",
            padding: "40px",
            background: "#f8fafc",
            borderRadius: "10px",
            color: "#94a3b8",
            fontSize: "14px",
            border: "1px dashed #e2e8f0",
          }}
        >
          No invoices found. Click "New Invoice" to create one.
        </div>
      ) : (
        <>
          <div
            style={{
              fontSize: "12px",
              color: "#94a3b8",
              marginBottom: "10px",
              fontWeight: 600,
            }}
          >
            Showing {filtered.length} invoice(s)
          </div>
          {filtered.map((inv) => (
            <InvoiceRow
              key={inv._id}
              inv={inv}
              onEdit={handleEdit}
              onDelete={handleDelete}
              onPrint={printInvoice}
            />
          ))}
        </>
      )}

      {/* Patient history summary */}
      {Object.keys(patientTotals).length > 0 && (
        <div style={{ ...card, marginTop: "28px" }}>
          <div
            style={{
              fontWeight: 700,
              fontSize: "13px",
              color: "#1e40af",
              marginBottom: "14px",
              textTransform: "uppercase",
              letterSpacing: "0.5px",
            }}
          >
            Patient Billing History
          </div>
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "repeat(auto-fill,minmax(200px,1fr))",
              gap: "10px",
            }}
          >
            {Object.entries(patientTotals)
              .sort((a, b) => b[1].total - a[1].total)
              .map(([pid, data]) => (
                <div
                  key={pid}
                  onClick={() => {
                    setFilterPatient(pid);
                  }}
                  style={{
                    background: "#f8fafc",
                    borderRadius: "8px",
                    padding: "10px 14px",
                    cursor: "pointer",
                    border: "1px solid #e5e7eb",
                  }}
                  onMouseEnter={(e) =>
                    (e.currentTarget.style.borderColor = "#2563eb")
                  }
                  onMouseLeave={(e) =>
                    (e.currentTarget.style.borderColor = "#e5e7eb")
                  }
                >
                  <div
                    style={{
                      fontWeight: 600,
                      fontSize: "13px",
                      color: "#1e293b",
                    }}
                  >
                    {data.name}
                  </div>
                  <div
                    style={{
                      fontSize: "12px",
                      color: "#64748b",
                      marginTop: "3px",
                    }}
                  >
                    {data.count} invoice(s)
                  </div>
                  <div
                    style={{
                      fontSize: "14px",
                      fontWeight: 800,
                      color: "#1e40af",
                      marginTop: "4px",
                    }}
                  >
                    {fmt(data.total)}
                  </div>
                </div>
              ))}
          </div>
        </div>
      )}

      {/* Top services */}
      {summary?.topServices?.length > 0 && (
        <div style={{ ...card, marginTop: "16px" }}>
          <div
            style={{
              fontWeight: 700,
              fontSize: "13px",
              color: "#1e40af",
              marginBottom: "14px",
              textTransform: "uppercase",
              letterSpacing: "0.5px",
            }}
          >
            Top Billed Treatments
          </div>
          {summary.topServices.map((s, i) => {
            const maxAmt = summary.topServices[0].amount || 1;
            const pct = Math.round((s.amount / maxAmt) * 100);
            return (
              <div key={i} style={{ marginBottom: "10px" }}>
                <div
                  style={{
                    display: "flex",
                    justifyContent: "space-between",
                    fontSize: "12px",
                    marginBottom: "4px",
                  }}
                >
                  <span style={{ color: "#334155", fontWeight: 500 }}>
                    {s.name}
                  </span>
                  <span style={{ color: "#1e40af", fontWeight: 700 }}>
                    {fmt(s.amount)}
                  </span>
                </div>
                <div
                  style={{
                    background: "#e5e7eb",
                    borderRadius: "20px",
                    height: "6px",
                  }}
                >
                  <div
                    style={{
                      background: "#1e40af",
                      borderRadius: "20px",
                      height: "6px",
                      width: `${pct}%`,
                    }}
                  />
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}
